import pika
import json
import time
import sys
from datetime import datetime
import threading


class RabbitMQPublisher:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        
    def publish_task(self, task_data):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        message = json.dumps({
            'task_data': task_data,
            'timestamp': datetime.now().isoformat(),
            'task_id': f"task_{int(time.time() * 1000)}"
        })
        
        self.channel.basic_publish(
            exchange='',
            routing_key=self.queue_name,
            body=message,
            properties=pika.BasicProperties(
                delivery_mode=2,
            )
        )
        print(f"Published task: {message}")
        
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


class RabbitMQConsumer:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        self.channel.basic_qos(prefetch_count=1)
        
    def process_task(self, task_message):
        print(f"Processing task: {task_message}")
        task_data = json.loads(task_message)
        
        if 'task_data' in task_data:
            time.sleep(2)
            print(f"Task {task_data.get('task_id')} completed successfully")
        else:
            print("Invalid task format")
            
    def callback(self, ch, method, properties, body):
        print(f"Received message: {body.decode()}")
        try:
            self.process_task(body.decode())
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f"Error processing task: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            
    def start_consuming(self):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.callback
        )
        
        print(f"Waiting for messages on queue '{self.queue_name}'. To exit press CTRL+C")
        self.channel.start_consuming()
        
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


def run_publisher():
    publisher = RabbitMQPublisher()
    
    try:
        publisher.connect()
        
        tasks = [
            {'operation': 'process_data', 'data': 'dataset_1'},
            {'operation': 'generate_report', 'report_id': 101},
            {'operation': 'send_email', 'recipient': 'user@example.com'},
            {'operation': 'backup_database', 'database': 'main_db'},
            {'operation': 'cleanup_cache', 'cache_type': 'redis'}
        ]
        
        for task in tasks:
            publisher.publish_task(task)
            time.sleep(1)
            
    except KeyboardInterrupt:
        print("Publisher interrupted")
    finally:
        publisher.close()


def run_consumer():
    consumer = RabbitMQConsumer()
    
    try:
        consumer.connect()
        consumer.start_consuming()
    except KeyboardInterrupt:
        print("Consumer interrupted")
    finally:
        consumer.close()


def run_multiple_consumers(num_consumers=3):
    consumers = []
    threads = []
    
    def start_consumer(consumer_id):
        consumer = RabbitMQConsumer()
        consumers.append(consumer)
        try:
            consumer.connect()
            print(f"Consumer {consumer_id} started")
            consumer.start_consuming()
        except KeyboardInterrupt:
            pass
        finally:
            consumer.close()
    
    for i in range(num_consumers):
        thread = threading.Thread(target=start_consumer, args=(i+1,))
        thread.daemon = True
        threads.append(thread)
        thread.start()
    
    try:
        for thread in threads:
            thread.join()
    except KeyboardInterrupt:
        print("\nShutting down consumers...")


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage:")
        print("  python app.py publisher - Run publisher")
        print("  python app.py consumer - Run single consumer")
        print("  python app.py multi_consumer [num] - Run multiple consumers")
        sys.exit(1)
    
    mode = sys.argv[1]
    
    if mode == 'publisher':
        run_publisher()
    elif mode == 'consumer':
        run_consumer()
    elif mode == 'multi_consumer':
        num = int(sys.argv[2]) if len(sys.argv) > 2 else 3
        run_multiple_consumers(num)
    else:
        print(f"Unknown mode: {mode}")
        sys.exit(1)